from typing import List
from itertools import combinations

def solve(nums: List[int], edges: List[List[int]]) -> int:
    n = len(nums)
    # Build adjacency list
    adj = [[] for _ in range(n)]
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    # Function to check if a subset is connected
    def is_connected(subset: List[int]) -> bool:
        if not subset:
            return False
        start = subset[0]
        visited = set()
        queue = [start]
        visited.add(start)
        while queue:
            node = queue.pop(0)
            for neighbor in adj[node]:
                if neighbor in subset and neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return len(visited) == len(subset)

    # Count valid subsets
    count = 0
    for size in range(1, n + 1):
        for subset in combinations(range(n), size):
            if is_connected(list(subset)):
                total = sum(nums[i] for i in subset)
                if total % 2 == 0:
                    count += 1
    return count
